THE CLAIM:
{
 "title": "EU Cyber Resilience Act could block Year-1 tenders with big operators",
 "narrative": "The model assumes a networked PDU sells like any CE-marked product, backed by EN 50600, ecodesign 2019/424 and CE/TÜV. But the Cyber Resilience Act covers this product too, its reporting duties start 11 September 2026 inside the first year, and large operators are already writing CRA clauses into 2026 tenders. A pre-launch entrant cannot show a credible CRA file that fast, so both reachable demand and Year-1 pace are overstated.",
 "mechanism": [
  {
   "step": "trigger",
   "text": "CRA covers networked PDUs: reporting from Sep 2026, conformity from Dec 2027.",
   "refs": [
    "profile:Product",
    "profile:Stage",
    "digest:serviceable-benchmark#c10"
   ]
  },
  {
   "step": "propagation",
   "text": "Large operators demand CRA readiness in 2026 tenders, screening out the entrant.",
   "refs": [
    "ledger:cust.operator-large",
    "digest:serviceable-benchmark#c12",
    "digest:serviceable-benchmark#c13"
   ]
  },
  {
   "step": "model-impact",
   "text": "Cert stack omits CRA, so reach and Year-1 pace look too high.",
   "refs": [
    "ledger:serviceableFactor",
    "ledger:obtainableFactor"
   ]
  }
 ],
 "falsifier": "A sample of 2026 large-operator power tenders with no CRA or SBOM clauses, plus proof the PDU is default class with self-assessment and a file completable before launch.",
 "category": "exogenous",
 "evidence": [
  {
   "title": "CRA Product Classification: Default, Important, Critical",
   "sourceType": "industry-report",
   "publisher": "CRA Evidence",
   "date": "2026-05-08",
   "excerpt": "Default products can usually use internal control, based on Module A. ... about 90% of products fall into the Default category.",
   "url": "https://craevidence.com/cra-compliance/product-classification",
   "attached": true
  },
  {
   "title": "What Are CRA Harmonised Standards? Status and Tracker",
   "sourceType": "industry-report",
   "publisher": "CRA Evidence",
   "date": "2026-06-04",
   "excerpt": "No CRA harmonised standard is published in the Official Journal yet (as of 4 June 2026), so the Article 27 presumption of conformity is not available for any product category.",
   "url": "https://craevidence.com/cra-compliance/harmonised-standards-status",
   "attached": true
  },
  {
   "title": "EU Cyber Resilience Act: CRA Compliance Guide 2026",
   "sourceType": "industry-report",
   "publisher": "Cloudsmith",
   "date": "2026-06-11",
   "excerpt": "On September 11, 2026, vulnerability reporting obligations go live... December 11, 2027, is the full compliance deadline, covering all remaining CRA software requirements, including SBOMs, secure-by-design, CE marking, and technical documentation for any new product placed on the EU market.",
   "url": "https://cloudsmith.com/blog/the-eu-cyber-resilience-act-what-engineering-teams-need-to-do-to-be-compliant",
   "attached": true
  }
 ]
}

THE LEDGER FACTS IT TARGETS (current values, derivations, bands):
[
 {
  "id": "serviceableFactor",
  "label": "Serviceable share of TAM",
  "kind": "assumption",
  "value": 0.55,
  "unit": "ratio",
  "confidence": "inferred",
  "maturity": "needs-source",
  "dimension": null,
  "dimensionValue": null,
  "sensitivityRange": {
   "low": 0.45,
   "high": 0.65
  },
  "funnelActive": true,
  "derivation": {
   "method": "Reachability assumption",
   "expression": "No public SAM/TAM benchmark for B2B hardware exists; EU cert stack (EN 50600, ecodesign 2019/424, CE/TÜV) justifies < 1.0 but doesn't quantify 0.55"
  },
  "provenance": {
   "rationale": "Assumption leaf — channel + regulatory reach; EU certification barriers documented qualitatively only.",
   "promotionPath": "Bottom-up channel-coverage model (named accounts × reachable share) → sourced serviceable %."
  },
  "evidence": [
   {
    "title": "EU ecodesign requirements for servers and data storage (2019/424)",
    "sourceType": "industry-report",
    "publisher": "EUR-Lex",
    "date": "2019",
    "excerpt": "EU ecodesign and certification requirements gate which demand is regulatory-clear for a new entrant — the qualitative basis of the serviceable haircut.",
    "attached": true
   }
  ]
 },
 {
  "id": "obtainableFactor",
  "label": "Year-1 obtainable share of SAM",
  "kind": "assumption",
  "value": 0.03,
  "unit": "ratio",
  "confidence": "inferred",
  "maturity": "triangulated",
  "dimension": null,
  "dimensionValue": null,
  "sensitivityRange": {
   "low": 0.01,
   "high": 0.05
  },
  "funnelActive": true,
  "derivation": {
   "method": "Benchmark anchoring",
   "expression": "Year-1 SOM benchmarks: 1% of SAM (Prospeo); early-stage range 1–5% (IdeaPlan) → curated 3% mid-band",
   "crossCheck": "Prior 6% assumption sat above every year-1 benchmark found — revised down"
  },
  "provenance": {
   "rationale": "Two independent benchmark sources agree on 1–5%, but both are generic (not DC-hardware-specific) → inferred.",
   "promotionPath": "Replace with pipeline-based model once first CE deals close (win-rate × cycle time × capacity)."
  },
  "evidence": [
   {
    "title": "Addressable markets — SOM benchmarks",
    "sourceType": "analyst-estimate",
    "publisher": "Prospeo",
    "date": null,
    "excerpt": "SOM benchmarks that won't get you laughed out of the room: 1% of SAM in Year 1, 3% in Year 2, 5% in Year 3.",
    "attached": true
   },
   {
    "title": "Serviceable Obtainable Market (SOM) — early-stage ranges",
    "sourceType": "analyst-estimate",
    "publisher": "IdeaPlan",
    "date": "2024",
    "excerpt": "For early-stage companies, SOM is typically 1-5% of SAM. For growing companies with product-market fit, SOM can reach 10-20% of SAM.",
    "attached": true
   }
  ]
 }
]

Emit JSON: { resolution: "error"|"risk", settleTest, proposedCorrection: {nodeId, value, low, high, rationale} or null, researchQueries: [{query, kind}] ([] for risks) }
